import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{r as e,o as p,c as o,a as n,d as s,b as i,f as c}from"./app-7cfa41e7.js";const l={},r=c(`<h1 id="字符串" tabindex="-1"><a class="header-anchor" href="#字符串" aria-hidden="true">#</a> 字符串</h1><p>Java里面字符串分为String ,StringBuilder和StringBuffer</p><h3 id="三种字符串类的区别" tabindex="-1"><a class="header-anchor" href="#三种字符串类的区别" aria-hidden="true">#</a> 三种字符串类的区别</h3><hr><ul><li>三者共同之处都是final类，不允许被继承</li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>String是一个长度不可变的字符序列，底层是一个被final修饰的char[]数组
StringBuffer是线程安全的可变字符串序列，效率低，底层是char[]数组存储
StringBuilder是非线程安全的可变字符串序列，效率高，底层是chart[]数组存储
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><p>运行速度：因为StringBuilder是线程不安全的，所有的公开方法没有加锁的，但是StringBuffer是线程安全的，所有的公开方法都是同步的（synchronized）的，所以StringBuilder的速度要大于StringBuffer，而String是最慢的,因为需要不断地开辟空间，而StringBuilder和StringBuffer则是直接对该对象进行更改的。</p></li><li><p>线程安全问题：StringBuilder线程不安全，StringBuffer线程安全</p></li><li><p>总结：</p><p>String：适用于<strong>少量的字符串操作</strong>的情况<br> StringBuilder：适用于****单线程*<em><strong>下在</strong>字符缓冲区进行大量操作的情况</em>*<br> StringBuffer：适用<strong>多线程</strong>下在<strong>字符缓冲区进行大量操作的情况</strong></p></li></ul><h3 id="string拼接方式" tabindex="-1"><a class="header-anchor" href="#string拼接方式" aria-hidden="true">#</a> String拼接方式</h3><hr><p>当我们执行 “str += &quot; World&quot;;”时底层其实走四步：</p><p>先创建一个StringBuilder对象，并调用无参数的构造方法。<br> StringBuilder对象调用append方法，把str内部 “Hello” 拼接到内部。<br> StringBuilder对象再次调用append方法，把 &quot; World&quot; 拼接到内部。<br> 最后StringBuilder对象调用toString方法，把拼接好的字符串传给str。</p><p>所以String拼接会创建StringBuilder对象，这样的效率是低下的如果在大量拼接的场景下</p><h3 id="string内存模型" tabindex="-1"><a class="header-anchor" href="#string内存模型" aria-hidden="true">#</a> String内存模型</h3><hr><p>一般分为编译期和运行期，如果能够在编译期读取的字符串字面值会直接指向字符串常量池地址</p><p>运行期进行拼接会调用StringBuilder创建StringBuilder对象，然后toString方法生成一个新的String对象。</p><p>首先来个代码：</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> test2 <span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token class-name">String</span> a<span class="token operator">=</span><span class="token keyword">new</span> <span class="token class-name">String</span><span class="token punctuation">(</span><span class="token string">&quot;1&quot;</span><span class="token punctuation">)</span><span class="token operator">+</span><span class="token keyword">new</span> <span class="token class-name">String</span><span class="token punctuation">(</span><span class="token string">&quot;1&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        a<span class="token punctuation">.</span><span class="token function">intern</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token class-name">String</span> b<span class="token operator">=</span><span class="token string">&quot;11&quot;</span><span class="token punctuation">;</span>
        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>a<span class="token operator">==</span>b<span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里的结果会输出true，我们会在字符串常量池中创建“1”，然后Heap中生成了a的对象,但此时常量池中是没有&quot;11&quot;的，此时我们再使用a.intern，如果在jdk7以前我们会在常量池中创建&quot;11&quot;这个对象,而jdk7以后，常量池不需要再储存一份对象了，而是直接引用a的对象，b直接会去常量池创建，但此时发现有了&quot;11&quot;的引用，所以b会指向堆中的a</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">String</span> s1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">String</span><span class="token punctuation">(</span><span class="token string">&quot;1&quot;</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token keyword">new</span> <span class="token class-name">String</span><span class="token punctuation">(</span><span class="token string">&quot;1&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//s1变量记录的地址为：new String</span>
s1<span class="token punctuation">.</span><span class="token function">intern</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//在字符串常量池中生成&quot;11&quot;。如何理解：jdk6：创建了一个新的对象&quot;11&quot;，也就有新的地址；jdk7：此时常量池中并没有创建&quot;11&quot;，而是创建了一个指向堆空间中new String(&quot;11&quot;)的地址；</span>
<span class="token class-name">String</span> s2 <span class="token operator">=</span> <span class="token string">&quot;11&quot;</span><span class="token punctuation">;</span>
<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>s1 <span class="token operator">==</span> s2<span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//jdk6:false;jdk7:true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/blog/image-20230510150352343.png" alt="image-20230510150352343" tabindex="0" loading="lazy"><figcaption>image-20230510150352343</figcaption></figure>`,21),u={href:"https://www.cnblogs.com/r1-12king/p/15946648.html",target:"_blank",rel:"noopener noreferrer"},d=n("p",null,"JDK7过后常量池就在Heap中了",-1),k=n("figure",null,[n("img",{src:"https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/blog/38b89647e0ec4207ab74d1b30087919f.png",alt:"在这里插入图片描述",tabindex:"0",loading:"lazy"}),n("figcaption",null,"在这里插入图片描述")],-1);function g(m,v){const a=e("ExternalLinkIcon");return p(),o("div",null,[r,n("p",null,[s("一篇不错的String文章："),n("a",u,[s("https://www.cnblogs.com/r1-12king/p/15946648.html"),i(a)])]),d,k])}const S=t(l,[["render",g],["__file","4.html.vue"]]);export{S as default};
